// Generated by OrchestKit Claude Plugin
// Created: 2026-06-11

// Unit tests for the top-level markdown route handlers (auth.md, api-policy.md,
// llms.txt). These are pure synchronous GET() functions over lib/constants —
// no network, no MSW. Guards the headers contract, the orank-scored policy
// claims, and internal link integrity via isServedPath().

import { describe, expect, it, vi } from "vitest";

// llms.txt imports @/lib/docs-content, which loads the generated fumadocs
// source (MDX) — un-transformable in vitest. Mock it with a minimal fixture;
// the section list is not what these tests assert.
vi.mock("@/lib/docs-content", () => ({
	SECTION_ORDER: ["getting-started"],
	orderedPages: () => [
		{ slugs: ["getting-started"], url: "/docs/getting-started" },
	],
}));

import { GET as getApiPolicy } from "@/app/api-policy.md/route";
import { GET as getAuthMd } from "@/app/auth.md/route";
import { GET as getLlmsTxt } from "@/app/llms.txt/route";
import { isServedPath } from "@/lib/agent-404";
import { SITE } from "@/lib/constants";

async function body(res: Response): Promise<string> {
	return await res.text();
}

// Extract markdown link targets: [label](target)
function linkTargets(md: string): string[] {
	return [...md.matchAll(/\]\(([^)\s]+)\)/g)].map((m) => m[1]);
}

describe("markdown route headers contract", () => {
	it.each([
		["api-policy.md", getApiPolicy, "text/markdown; charset=utf-8"],
		["auth.md", getAuthMd, "text/markdown; charset=utf-8"],
		["llms.txt", getLlmsTxt, "text/plain; charset=utf-8"],
	] as const)("%s returns 200 with type + cache headers", (_name, get, type) => {
		const res = get();
		expect(res.status).toBe(200);
		expect(res.headers.get("Content-Type")).toBe(type);
		expect(res.headers.get("Cache-Control")).toBe("public, max-age=3600");
	});
});

describe("api-policy.md scored policy claims", () => {
	it("carries the versioning + deprecation claims the checker scores", async () => {
		const md = await body(getApiPolicy());
		for (const claim of [
			"## Versioning",
			"RFC 8594",
			"at least 6 months",
			"410 Gone",
			"## Webhooks",
			"does not emit webhooks",
		]) {
			expect(md).toContain(claim);
		}
	});
});

describe("auth.md additions", () => {
	it("cross-links the API policy page and states webhook non-support", async () => {
		const md = await body(getAuthMd());
		expect(md).toContain("## Webhooks");
		expect(md).toContain("/api-policy.md");
	});

	it("explains the canonical auth.md error codes do not apply", async () => {
		const md = await body(getAuthMd());
		expect(md).toContain("registration_not_supported");
		expect(md).toContain("insufficient_scope");
	});
});

describe("llms.txt advertised surfaces", () => {
	it("advertises the stdio docker image", async () => {
		const txt = await body(getLlmsTxt());
		expect(txt).toContain("ghcr.io/yonatangross/orchestkit-docs-mcp");
		expect(txt).toContain("docker run -i --rm");
	});

	it("links the PyPI package and the API policy page", async () => {
		const txt = await body(getLlmsTxt());
		expect(txt).toContain("https://pypi.org/project/orchestkit-hook-contract/");
		expect(txt).toContain("/api-policy.md");
	});
});

describe("internal link integrity", () => {
	it("every internal markdown link resolves to a served path", async () => {
		const docs = [
			await body(getApiPolicy()),
			await body(getAuthMd()),
			await body(getLlmsTxt()),
		];
		for (const md of docs) {
			for (const target of linkTargets(md)) {
				// Absolute site-domain links: strip the domain and check the path.
				const normalized = target.startsWith(SITE.domain)
					? target.slice(SITE.domain.length)
					: target;
				if (normalized.startsWith("/")) {
					const path = normalized.split("#")[0];
					expect(isServedPath(path), `unserved link target: ${target}`).toBe(
						true,
					);
				} else {
					// External links must be https; do NOT fetch them in unit tests.
					expect(normalized.startsWith("https://"), `non-https: ${target}`).toBe(
						true,
					);
				}
			}
		}
	});
});
